  ('fire-eq-eng-moex-01073', 'fire-eq-eng', 'fire-eq-eng-moex-098-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '以室內儲槽儲存閃火點在攝氏七十度以下之第四類公共危險物品之顯著滅火困難場所，依「各類場所消 防安全設備設置標準」設置冷卻撒水設備之規定，何者錯誤？', '["撒水噴孔符合CNS12854之規定，孔徑在四公厘以上", "撒水量按槽壁總防護面積每平方公尺每分鐘二公升以上計算之，其管徑依水力計算配置", "水源容量在最大一座儲槽連續放水三小時之水量以上", "加壓送水裝置啟動後五分鐘以內，能有效撒水，且加壓送水裝置距撒水區域在五百公尺以下。但設有 保壓措施者，不在此限"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "525d139079ff", "answer_pdf_sha1": "55834ab1f2a3", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
